252	    auto lexer_res = lexer.tokenize(template_str);
253	
254	    // compile to AST
255	    jinja::program ast = jinja::parse_from_tokens(lexer_res);
256	
257	    // check caps for workarounds
258	    jinja::caps_get(ast);
259	
260	    std::cout << "\n=== RUN ===\n";
261	    jinja::context ctx(template_str);
262	
263	    jinja::global_from_json(ctx, input, true);
264	
265	    jinja::runtime runtime(ctx);
266	    const jinja::value results = runtime.execute(ast);
267	    auto parts = jinja::runtime::gather_string_parts(results);
268	
269	    std::cout << "\n=== RESULTS ===\n";
270	    for (const auto & part : parts->as_string().parts) {
271	        std::cout << (part.is_input ? "DATA" : "TMPL") << ": " << part.val << "\n";
272	    }
273	
274	    return parts;
275	}
