        const auto * str = llama_model_chat_template(model, nullptr);  // default template
        if (str) default_template_src = str;

        str = llama_model_chat_template(model, "tool_use");  // optional tool-use variant
        if (str) template_tool_use_src = str;
    } else {
        default_template_src = chat_template_override;  // explicit override
