common_chat_templates_ptr common_chat_templates_init(
    const struct llama_model * model,
    const std::string & chat_template_override,
    const std::string & bos_token_override = "",
    const std::string & eos_token_override = "") {

    std::string default_template_src;

    if (chat_template_override.empty()) {
        // Load from model metadata
        const auto * str = llama_model_chat_template(model, nullptr);  // default template
        if (str) default_template_src = str;

        str = llama_model_chat_template(model, "tool_use");  // optional tool-use variant
        if (str) template_tool_use_src = str;
    } else {
        default_template_src = chat_template_override;  // explicit override
    }

    // Fallback to ChatML if no template found
    if (default_template_src.empty() || default_template_src == "chatml") {
        default_template_src = CHATML_TEMPLATE_SRC;
    }

    // Create Jinja template object (parses & compiles)
    tmpls->template_default = std::make_unique<common_chat_template>(
        default_template_src, token_bos, token_eos);

    return tmpls;
}
```

